const p = msg.payload;
const roll = Math.atan2(p.ay, p.az) * 180 / Math.PI;
const pitch = Math.atan2(-p.ax, Math.sqrt(p.ay*p.ay + p.az*p.az)) * 180 / Math.PI;
const gyroMag = Math.sqrt(p.gx*p.gx + p.gy*p.gy + p.gz*p.gz);
msg.payload = 'roll=' + roll.toFixed(1) + '° pitch=' + pitch.toFixed(1) + '° |gyro|=' + gyroMag.toFixed(3) + ' rad/s';
return msg;
